import{r as i,o as n,a as l,b as e,d as a,w as r,F as s,e as t,c as d}from"./app.970ef970.js";import{_ as c}from"./plugin-vue_export-helper.21dcd24c.js";const p={},h=e("h1",{id:"ibm-z-open-editor-mcp-tools",tabindex:"-1"},[e("a",{class:"header-anchor",href:"#ibm-z-open-editor-mcp-tools","aria-hidden":"true"},"#"),t(" IBM Z Open Editor MCP Tools")],-1),u=t("These are all the Model Context Protocol (MCP) capabilities available in Z Open Editor. See the section "),m=t("Agent Mode"),f=t(" for details."),g=d('<h2 id="zowe-profile-tools" tabindex="-1"><a class="header-anchor" href="#zowe-profile-tools" aria-hidden="true">#</a> Zowe Profile Tools</h2><p>You can ask about your Zowe\u2122 Client profiles to see what is available, what is in use by Z Open Editor, and to obtain or retire JSON Web Token (JWT) authentication.</p><table><thead><tr><th>Tool Name</th><th>Tool Description</th></tr></thead><tbody><tr><td><code>zowe-get-default-profile &lt;type&gt;</code></td><td>Retrieve the default Zowe profile of a given type as configured in the Zowe team configuration files, defaults to type RSE.</td></tr><tr><td><code>zopeneditor-get-default-zowe-profile</code></td><td>Retrieve IBM Z\xAE Open Editor&#39;s default Zowe profile as configured in the <code>zopeneditor.zowe</code> user settings.</td></tr><tr><td><code>zowe-profile-connection-check</code></td><td>Retrieve the status of the connection to the Rest API server. You can optionally specify <code>profileName</code> to run the check with a profile other than the IBM Z Open Editor default Zowe profile.</td></tr><tr><td><code>zowe-list-profiles &lt;type&gt;</code></td><td>List Zowe profiles configured in the Zowe team configuration file by type. Defaults to all profiles.</td></tr><tr><td><code>zowe-profile-login</code></td><td>Log in with the editor&#39;s set profile to obtain a JWT. You can optionally specify <code>profileName</code> to log in with a profile other than the IBM Z Open Editor default Zowe profile.</td></tr><tr><td><code>zowe-profile-logout</code></td><td>Log out from the server with the editor&#39;s set profile and remove the JWT from the team configuration file. You can optionally specify <code>profileName</code> to log out with a profile other than the IBM Z Open Editor default Zowe profile.</td></tr><tr><td><code>zopeneditor-change-default-zowe-profile</code></td><td>Change the IBM Z Open Editor default Zowe profile.</td></tr><tr><td><code>zowe-create-team-config</code></td><td>Launch the Zowe Explorer interactive team configuration creation workflow.</td></tr><tr><td><code>zowe-update-basic-credentials</code></td><td>Securely update username and password with the Zowe Explorer interactive VS Code prompts. Credentials are securely stored and never exposed to LLMs.</td></tr><tr><td><code>zowe-update-profile</code></td><td>Update non-sensitive profile connection properties (host, port, protocol, etc.).</td></tr></tbody></table><h2 id="zowe-mvs-tools" tabindex="-1"><a class="header-anchor" href="#zowe-mvs-tools" aria-hidden="true">#</a> Zowe MVS Tools</h2><p>You can manage data sets and members on z/OS\xAE and run TSO commands. All of these commands accept the optional <code>profileName</code> argument to specify the profile to use. If no profile is specified, the IBM Z Open Editor default profile is used.</p><table><thead><tr><th>Tool Name</th><th>Tool Description</th></tr></thead><tbody><tr><td><code>zowe-list-datasets &lt;filter&gt;</code></td><td>Retrieve data sets that match the specified filter pattern.</td></tr><tr><td><code>zowe-list-members &lt;dataSetName&gt;</code></td><td>List members of the specified data set.</td></tr><tr><td><code>zowe-get-dataset-content &lt;mvsFileName&gt;</code></td><td>Retrieve the contents of the specified SEQ or PDS member. You can optionally specify the <code>file</code> parameter to download the content to a local location.</td></tr><tr><td><code>zowe-allocate-like-dataset &lt;dataSetName&gt; &lt;existingDataSet&gt;</code></td><td>Allocate a new specified data set similar to an existing one.</td></tr><tr><td><code>zowe-issue-tso-command &lt;command&gt;</code></td><td>Run the specified TSO command.</td></tr><tr><td><code>zowe-search-dataset &lt;pattern&gt; &lt;searchString&gt;</code></td><td>Search data sets for content using a string or regex pattern. Optional parameters include: <code>regex</code> (default false), <code>caseSensitive</code> (default false), <code>searchExactName</code> (default true), <code>mainframeSearch</code> (default false), <code>getOptions</code>, and <code>listOptions</code>.</td></tr><tr><td><code>zowe-upload-dataset &lt;localPath&gt; &lt;dataSetName&gt;</code></td><td>Upload a local file to a data set.</td></tr></tbody></table><h2 id="zowe-unix-system-services-tools" tabindex="-1"><a class="header-anchor" href="#zowe-unix-system-services-tools" aria-hidden="true">#</a> Zowe UNIX System Services Tools</h2><p>You can manage files and directories in z/OS UNIX System Services and run UNIX System Services commands. Each command accepts the optional <code>profileName</code> argument to specify the profile to use. If no profile is specified, the IBM Z Open Editor default profile is used.</p><table><thead><tr><th>Tool Name</th><th>Tool Description</th></tr></thead><tbody><tr><td><code>zowe-list-unix-files &lt;filePath&gt;</code></td><td>List the UNIX System Services files in the specified path.</td></tr><tr><td><code>zowe-upload-unix-files &lt;localPath&gt; &lt;unixPath&gt;</code></td><td>Upload a local file to the specified location on UNIX System Services.</td></tr><tr><td><code>zowe-create-unix-path &lt;unixPath&gt; &lt;type&gt; &lt;permissions&gt;</code></td><td>Create a specified UNIX System Services file or directory at the specified path. Specify whether it is a file or directory. Permissions are optional; if omitted, the default value &#39;rwxrw-r--&#39; is used.</td></tr><tr><td><code>zowe-get-unix-file-content &lt;unixPath&gt;</code></td><td>Download the contents of the specified UNIX System Services file. You can use the optional <code>file</code> parameter to specify a local location to download content.</td></tr><tr><td><code>zowe-issue-unix-command &lt;unixCommand&gt;</code></td><td>Run the specified UNIX System Services command on the system.</td></tr><tr><td><code>zowe-upload-folder-to-unix &lt;localFolderPath&gt; &lt;unixFolderPath&gt;</code></td><td>Upload a local folder to the specified location on UNIX System Services.</td></tr></tbody></table><h2 id="zowe-jes-tools" tabindex="-1"><a class="header-anchor" href="#zowe-jes-tools" aria-hidden="true">#</a> Zowe JES Tools</h2><p>You can get information about z/OS jobs and spool files. Each command accepts the optional <code>profileName</code> argument to specify the profile to use. If no profile is specified, the IBM Z Open Editor default profile is used.</p><table><thead><tr><th>Tool Name</th><th>Tool Description</th></tr></thead><tbody><tr><td><code>zowe-list-jobs &lt;owner&gt; &lt;status&gt; &lt;jobName&gt; &lt;jobId&gt;</code></td><td>Retrieve jobs that match the specified owner, job status, job name, or job ID. If no parameters are specified, the command returns the jobs for the current user (owner) as defined in profile.</td></tr><tr><td><code>zowe-submit-dataset &lt;dataSet&gt;</code></td><td>Submit a job from the specified data set.</td></tr><tr><td><code>zowe-purge-job &lt;jobName&gt; &lt;jobId&gt;</code></td><td>Purge the job identified by the given job name and job ID.</td></tr><tr><td><code>zowe-submit-jcl &lt;jclString&gt;</code></td><td>Submit a job for the given local JCL.</td></tr><tr><td><code>zowe-list-job-spools &lt;jobName&gt; &lt;jobId&gt;</code></td><td>Retrieve the spools files for the specified job name and/or job ID.</td></tr><tr><td><code>zowe-get-single-job-spool-output &lt;jobName&gt; &lt;jobId&gt; &lt;spoolId&gt;</code></td><td>Retrieve the output of a job spool for the specified job name and/or job ID, and spool ID.</td></tr><tr><td><code>zowe-get-all-job-spools-output &lt;jobName&gt; &lt;jobId&gt; &lt;spoolId&gt;</code></td><td>Retrieve the output of all job spools for the specified job name and/or job ID. You can use the optional <code>outDir</code> parameter to specify a local directory to download files.</td></tr></tbody></table><h2 id="ibm-rse-api-tools" tabindex="-1"><a class="header-anchor" href="#ibm-rse-api-tools" aria-hidden="true">#</a> IBM RSE API Tools</h2><p>All of these commands accept the optional <code>profileName</code> argument to specify the profile to use. If no profile is specified, the IBM Z Open Editor default profile is used.</p><table><thead><tr><th>Tool Name</th><th>Tool Description</th></tr></thead><tbody><tr><td><code>rseapi-get-system-resource-consumption</code></td><td>Run DISPLAYACTIVE to retrieve system address space resource consumption information. This command is available only with an RSE profile.</td></tr><tr><td><code>rseapi-get-all-job-resource-consumption</code></td><td>Run DISPLAYACTIVE to retrieve resource consumption information for all active job address spaces. Only available with an RSE profile.</td></tr><tr><td><code>rseapi-download-unix-folder &lt;unixFolderPath&gt; &lt;localFolderPath&gt;</code></td><td>Download the specified z/OS UNIX System Services folder to the specified local folder. Optional parameters include <code>binaryMode</code>, <code>runInBackground</code>, <code>maxConcurrency</code>, and <code>overwriteExisting</code>.</td></tr></tbody></table><h2 id="zapp-tools" tabindex="-1"><a class="header-anchor" href="#zapp-tools" aria-hidden="true">#</a> ZAPP Tools</h2><p>You can ask about the property groups defined in your ZAPP files. This works across all ZAPP files in a multi-root workspace. You can ask the AI to list the locations it searches for include files and combine the result with the log file resource for troubleshooting.</p><table><thead><tr><th>Tool Name</th><th>Tool Description</th></tr></thead><tbody><tr><td><code>zapp-get-property-groups &lt;language&gt;</code></td><td>List all property groups defined for the specified language (required) in all workspaces.</td></tr></tbody></table><h2 id="z-open-editor-log-file-tool-and-resource" tabindex="-1"><a class="header-anchor" href="#z-open-editor-log-file-tool-and-resource" aria-hidden="true">#</a> Z Open Editor log file tool and resource</h2><p>You can access Z Open Editor&#39;s log file for troubleshooting by asking your AI questions about the editor&#39;s configuration and how it performed tasks, such as searching for include files using property groups from ZAPP files. You can also inquire about how features are configured or enabled in Z Open Editor. Depending on the Chat agent, it might prefer to run the MCP tool to read the log file or use the MCP Resource, both options are available.</p><p>For the best results, run the Z Open Editor logger in DEBUG mode as described in <a href="./locating_local_client_logs">Troubleshooting using log files</a>.</p><table><thead><tr><th>Tool Name</th><th>Tool Description</th></tr></thead><tbody><tr><td><code>zopeneditor-read-the-log</code></td><td>Read the current Z Open Editor log file and search the content.</td></tr></tbody></table><table><thead><tr><th>Resource Name</th><th>Description</th></tr></thead><tbody><tr><td><code>zopeneditor.log</code></td><td>The log file for Z Open Editor referred to as <code>zopeneditor.log</code> that can be used for troubleshooting and configuration information.</td></tr></tbody></table><h2 id="data-elements-view" tabindex="-1"><a class="header-anchor" href="#data-elements-view" aria-hidden="true">#</a> Data Elements view</h2><p>If you are analyzing your program, perhaps using code explanations tools, you can also ask the API to open Z Open Editor&#39;s Data Elements view to get a sortable representation of the program&#39;s symbols that can be filtered and searched.</p><table><thead><tr><th>Tool Name</th><th>Tool Description</th></tr></thead><tbody><tr><td><code>zopeneditor-show-data-elements-view</code></td><td>Open the Data Elements view for a program specified by name or the currently open program.</td></tr></tbody></table><h2 id="dependency-based-build-dbb-tools" tabindex="-1"><a class="header-anchor" href="#dependency-based-build-dbb-tools" aria-hidden="true">#</a> Dependency Based Build (DBB) Tools</h2><table><thead><tr><th>Tool Name</th><th>Tool Description</th></tr></thead><tbody><tr><td><code>dbb-get-build-result &lt;buildResult&gt; &lt;buildGroup&gt;</code></td><td>Gets an IBM Dependency Based Build (DBB) build result that collects the metadata information of a DBB build.</td></tr><tr><td><code>dbb-get-last-failed-build-result &lt;buildGroup&gt;</code></td><td>Gets the last failed IBM Dependency Based Build (DBB) build result, which collects the metadata information of the last failed DBB build in a particular DBB group.</td></tr><tr><td><code>dbb-download-build-result-attachments &lt;buildResult&gt; &lt;buildGroup&gt;</code></td><td>Exports all of the attachments from an IBM Dependency Based Build (DBB) build result on a remote environment and downloads them to a local folder. The path to the local folder is returned from this tool.</td></tr></tbody></table><h2 id="user-build" tabindex="-1"><a class="header-anchor" href="#user-build" aria-hidden="true">#</a> User build</h2><table><thead><tr><th>Tool Name</th><th>Tool Description</th></tr></thead><tbody><tr><td><code>userbuild-run-user-build &lt;buildFile&gt; &lt;fullUpload&gt;</code></td><td>Runs a DBB user build on a file and returns the runtime report of its execution. Before execution, ask the user whether they want to perform a full upload, providing a button prompt for them to click if supported by the LLM. If the build succeeds, summarize its execution. If an error occurs as recorded in the runtime report, explain how the error occurred and how the user might fix it. If log files contain error information relevant to diagnosing the issue, ask the user whether they want you to read them and provide further analysis. If &quot;errorFeedback&quot; information is returned, it is saved in the user&#39;s VS Code Problems view for the file that was built. Pay special attention to the information in the &quot;importantNotices&quot; section of this tool&#39;s output, this is the most important information.</td></tr><tr><td><code>userbuild-get-dbb-log &lt;filename&gt;</code></td><td>Returns the contents of a DBB log from the most recent user build. These logs are downloaded from the remote host and stored in a local log directory after a user build. They provide detailed troubleshooting information on build steps such as compilation error logs.</td></tr></tbody></table><h2 id="program-analysis-tools" tabindex="-1"><a class="header-anchor" href="#program-analysis-tools" aria-hidden="true">#</a> Program analysis tools</h2><p>Connecting your AI to parsed program metadata enables deeper analysis and provide accurate insights into your programs. These tools answer queries about the impact of modifying data items and help analyze program structure.</p><table><thead><tr><th>Tool Name</th><th>Tool Description</th></tr></thead><tbody><tr><td><code>zopeneditor-cobol-get-data-flow &lt;programName&gt; &lt;dataItemName&gt; &lt;line&gt; &lt;character&gt;</code></td><td>Traces data flow for a specific COBOL data item and returns a graph representation of how the item is modified in the program. Use this tool to analyze the impact of modifying COBOL data items or to summarize how they are used.</td></tr><tr><td><code>zopeneditor-cobol-get-program-control-flow &lt;programName&gt; &lt;includeExitNodes&gt;</code></td><td>Retrieves parsed control flow data from the COBOL Language Server to analyze program structure and execution paths.</td></tr><tr><td><code>zopeneditor-pli-get-program-control-flow &lt;programName&gt; &lt;includeExitNodes&gt;</code></td><td>Retrieves parsed control flow data from the PL/I Language Server to analyze program structure and execution paths.</td></tr></tbody></table><h2 id="languages-specific-tools" tabindex="-1"><a class="header-anchor" href="#languages-specific-tools" aria-hidden="true">#</a> Languages specific tools</h2>',34),b=e("thead",null,[e("tr",null,[e("th",null,"Tool Name"),e("th",null,"Tool Description")])],-1),y=e("tr",null,[e("td",null,[e("code",null,"zopeneditor-get-embedded-languages <programName>")]),e("td",null,"Detects embedded languages in a COBOL or PL/I file. This tool identifies whether a COBOL or PL/I program contains CICS, SQL, DLI, or MQ operations.")],-1),w=e("tr",null,[e("td",null,[e("code",null,"zopeneditor-cobol-renumber-file <leftArea> <rightArea> <programName>")]),e("td",null,"Renumbers a COBOL file using the COBOL Language Server to add sequence numbers to every line in the file. Sequence numbers can be inserted in the left column, the right column, or both. The tool expects a filename with or without a file extension.")],-1),v=e("tr",null,[e("td",null,[e("code",null,"zopeneditor-cobol-unnumber-file <leftArea> <rightArea> <programName>")]),e("td",null,"Removes sequence numbers from every line in a COBOL file using the COBOL Language Server. Sequence numbers can be removed from the left column, the right column, or both. The tool expects a filename with or without a file extension.")],-1),_=e("td",null,[e("code",null,"zopeneditor-cobol-format-file <programName>")],-1),S=t("Formats a COBOL file using the COBOL Language Server and a Z Code Format file. The tool expects a filename with or without the file extension, and it also expects the user to have a Z Code Format file named zcodeformat.yaml or zcodeformat.json in the workspace. See "),z=t("Experimental: Formatting COBOL source code"),O=t("."),I=e("tr",null,[e("td",null,[e("code",null,"zopeneditor-cobol-renumber-multiple-files <leftArea> <rightArea> <searchPatterns>")]),e("td",null,"Renumbers multiple COBOL files in the workspace using the COBOL Language Server. Sequence numbers are added to every line in the files and can be inserted in the left column, the right column, or both. The tool expects a list of filenames or a glob pattern to search the workspace.")],-1),x=e("tr",null,[e("td",null,[e("code",null,"zopeneditor-cobol-unnumber-multiple-files <leftArea> <rightArea> <searchPatterns>")]),e("td",null,"Removes sequence numbers from every line in multiple COBOL files in the workspace using the COBOL Language Server. Sequence numbers can be removed from the left column, the right column, or both. The tool expects a list of filenames or a glob pattern to search the workspace.")],-1),D=e("td",null,[e("code",null,"zopeneditor-cobol-format-multiple-files <searchPatterns>")],-1),B=t("Formats multiple COBOL files using the COBOL Language Server and a Z Code Format file. The tool expects a list of filenames or a glob pattern to search the workspace, and it also expects the user to have a Z Code Format file named zcodeformat.yaml or zcodeformat.json in the workspace. See "),L=t("Experimental: Formatting COBOL source code"),T=t("."),Y=e("tr",null,[e("td",null,[e("code",null,"zcodescan-check-current-program")]),e("td",null,"Run an IBM ZCodeScan on the COBOL or PL/I program file currently open in the editor. The scan parses the program and returns linter-style issues about the quality of the program. Use the results returned to provide a detailed summary of the problems found and propose ways to fix them referencing COBOL or PL/I best practices. If possible provide examples for how the problems described could be fixed. If the scan results contain errors, list the error code and message.")],-1),N=e("tr",null,[e("td",null,[e("code",null,"zcodescan-check-list-of-local-programs <searchPatterns>")]),e("td",null,"Run an IBM ZCodeScan on COBOL or PL/I files in your local workspace. The files are identifies by a list of Glob search patterns that define all the programs to be scanned in the editor workspace. The scan parses all programs and returns linter-style issues about the quality of the programs. Use the results returned to provide a detailed summary of the problems found and propose ways to fix them referencing COBOL or PL/I best practices. Group the results by listing the most significant problems by severity and number of occurrences found. If possible provide examples for how the problems described could be fixed. If the scan results contain errors, list the error code and message.")],-1),k=d('<h2 id="wazi-deploy-evidence-tools" tabindex="-1"><a class="header-anchor" href="#wazi-deploy-evidence-tools" aria-hidden="true">#</a> Wazi Deploy Evidence tools</h2><table><thead><tr><th>Tool Name</th><th>Tool Description</th></tr></thead><tbody><tr><td><code>check-evidence-version</code></td><td>Checks and returns the &quot;wazideploy-evidence&quot; version on the system.</td></tr><tr><td><code>index-evidence-folder</code></td><td>Indexes the evidence folder defined in user settings. The Data Folder and Index Folder must be defined. Returns information on modified files. This tool must be run before any queries.</td></tr><tr><td><code>list-deployments &lt;status&gt; &lt;environment_name&gt; &lt;artifact_name&gt; &lt;artifact_type&gt; &lt;application_name&gt; &lt;application_version&gt; &lt;package_path&gt; &lt;deployed_before YYYYMMDD.HHmmSS.sss&gt; &lt;deployed_after YYYYMMDD.HHmmSS.sss&gt; &lt;history true|false&gt;</code></td><td>Lists deployments in reverse chronological order. Includes deploy timestamp, evidence file path, environment name, application name and version, package path, deployment end status, and deployed artifacts (<code>&lt;name&gt;.&lt;type&gt;</code>). By default, only deployments with end status <code>Ok</code> are returned. Supports filtering by status, environment name, artifact name, artifact type, application name, application version, package path, deployment time range, and history flag. Glob patterns are accepted for string filters. Outputs a multi-document YAML description with one document per deployment.</td></tr><tr><td><code>list-environments &lt;environment_name&gt; &lt;artifact_name&gt; &lt;artifact_type&gt; &lt;application_name&gt; &lt;application_version&gt; &lt;package_path&gt; &lt;deployed_before YYYYMMDD.HHmmSS.sss&gt; &lt;deployed_after YYYYMMDD.HHmmSS.sss&gt; &lt;history true|false&gt;</code></td><td>Lists environments in ascending alphanumerical order. Includes deployed artifacts (<code>&lt;name&gt;.&lt;type&gt;</code>), deploy timestamp, application name and version, and package path. Supports filtering by environment name, artifact name, artifact type, application name, application_version, package path, deployment time range, and history flag. Glob patterns are accepted for string filters. Outputs a multi-document YAML description with one document per environment. Depending on the history flag, each artifact includes either the last deployment details or the full chronological list of deployments.</td></tr><tr><td><code>list-artifacts &lt;artifact_name&gt; &lt;artifact_type&gt; &lt;environment_name&gt; &lt;application_name&gt; &lt;application_version&gt; &lt;package_path&gt; &lt;deployed_before YYYYMMDD.HHmmSS.sss&gt; &lt;deployed_after YYYYMMDD.HHmmSS.sss&gt; &lt;history true|false&gt;</code></td><td>Lists deployed artifacts in ascending alphanumerical order of <code>&lt;name&gt;.&lt;type&gt;</code>. Includes environment name, deploy timestamp, application name and version, and deployed package path. Supports filtering by artifact name, artifact type, environment name, application name, application version, package path, deployment time range, and history flag. Glob patterns are accepted for string filters. Outputs a multi-document YAML description with one document per artifact. Each document contains the artifact (<code>artifact</code>) and a list of environments (<code>environments</code>). Depending on the history flag, each environment includes either the last deployment details or the full chronological list of deployments.</td></tr><tr><td><code>list-packages &lt;artifact_name&gt; &lt;artifact_type&gt; &lt;environment_name&gt; &lt;application_name&gt; &lt;application_version&gt; &lt;package_path&gt; &lt;deployed_before YYYYMMDD.HHmmSS.sss&gt; &lt;deployed_after YYYYMMDD.HHmmSS.sss&gt; &lt;history true|false&gt;</code></td><td>Lists deployed package paths in ascending alphanumerical order. Includes application name and version, artifact names, deploy timestamp, and environment name. Supports filtering by artifact name, artifact type, environment name, application name, application version, package path, deployment time range, and history flag. Glob patterns are accepted for string filters. Outputs a multi-document YAML description with one document per package path. Each document contains the package path (<code>package_path</code>), a list of artifacts, and a list of environments (<code>environments</code>). Depending on the history flag, each environment includes either the last deployment timestamp or the full list of deployment timestamps in chronological order.</td></tr><tr><td><code>list-failures &lt;limit number&gt; &lt;environment_name&gt; &lt;application_name&gt; &lt;application_version&gt; &lt;package_path&gt; &lt;deployed_before YYYYMMDD.HHmmSS.sss&gt; &lt;deployed_after YYYYMMDD.HHmmSS.sss&gt;</code></td><td>Lists deployment failures in reverse chronological order. Includes deploy timestamp, target environment name, failure location, and detailed failure data. By default, returns the last 10 failures; use <code>limit 0</code> for no limit. Supports filtering by environment name, application name, application version, package path, and deployment time range. Glob patterns are accepted for string filters. Outputs a multi-document YAML description with one document per deployment. Each document contains the deploy timestamp (<code>deploy_timestamp</code>), environment name (<code>environment_name</code>), and a list of failures (<code>failures</code>) with location and detailed information.</td></tr><tr><td><code>list-field-values &lt;fieldname&gt; &lt;parent_fieldname&gt;</code></td><td>Lists all values of a specified field. The <code>fieldname</code> argument is required and identifies the target field. The <code>parent_fieldname</code> can restrict the search to fields under a specific parent field. Outputs a multi-document YAML description where each document contains a field named <code>fieldname values</code> with the list of all values associated with the specified field.</td></tr></tbody></table>',2);function M(C,E){const o=i("RouterLink");return n(),l(s,null,[h,e("p",null,[u,a(o,{to:"/Docs/advanced_agent_mode.html"},{default:r(()=>[m]),_:1}),f]),g,e("table",null,[b,e("tbody",null,[y,w,v,e("tr",null,[_,e("td",null,[S,a(o,{to:"/Docs/zcodeformatting.html"},{default:r(()=>[z]),_:1}),O])]),I,x,e("tr",null,[D,e("td",null,[B,a(o,{to:"/Docs/zcodeformatting.html"},{default:r(()=>[L]),_:1}),T])]),Y,N])]),k],64)}var j=c(p,[["render",M]]);export{j as default};
